type lzma_block is record
   version : aliased Interfaces.C.unsigned;
   header_size : aliased Interfaces.C.unsigned;
   check : aliased Lzma.Check.lzma_check;
   compressed_size : aliased Lzma.Vli.lzma_vli;
   uncompressed_size : aliased Lzma.Vli.lzma_vli;
   filters : access Lzma.Filter.lzma_filter;
   raw_check : aliased lzma_block_raw_check_array;
   reserved_ptr1 : System.Address;
   reserved_ptr2 : System.Address;
   reserved_ptr3 : System.Address;
   reserved_int1 : aliased Interfaces.C.unsigned;
   reserved_int2 : aliased Interfaces.C.unsigned;
   reserved_int3 : aliased Lzma.Vli.lzma_vli;
   reserved_int4 : aliased Lzma.Vli.lzma_vli;
   reserved_int5 : aliased Lzma.Vli.lzma_vli;
   reserved_int6 : aliased Lzma.Vli.lzma_vli;
   reserved_int7 : aliased Lzma.Vli.lzma_vli;
   reserved_int8 : aliased Lzma.Vli.lzma_vli;
   reserved_enum1 : aliased Lzma.Base.lzma_reserved_enum_type;
   reserved_enum2 : aliased Lzma.Base.lzma_reserved_enum_type;
   reserved_enum3 : aliased Lzma.Base.lzma_reserved_enum_type;
   reserved_enum4 : aliased Lzma.Base.lzma_reserved_enum_type;
   reserved_bool1 : aliased Lzma.Base.lzma_bool;
   reserved_bool2 : aliased Lzma.Base.lzma_bool;
   reserved_bool3 : aliased Lzma.Base.lzma_bool;
   reserved_bool4 : aliased Lzma.Base.lzma_bool;
   reserved_bool5 : aliased Lzma.Base.lzma_bool;
   reserved_bool6 : aliased Lzma.Base.lzma_bool;
   reserved_bool7 : aliased Lzma.Base.lzma_bool;
   reserved_bool8 : aliased Lzma.Base.lzma_bool;
end record;

